<script setup>
import { ref, onMounted, onBeforeUnmount, watch } from 'vue';

const props = defineProps({
  rows: { type: Array, default: () => [] }
});
const emit = defineEmits(['summary']);
const worker = new Worker(new URL('../workers/profile.worker.js', import.meta.url), { type:'module' });

const state = ref(null);
const loading = ref(false);
const error = ref('');

function emitSummary() {
  emit('summary', {
    loading: loading.value,
    error: error.value,
    sampleCount: state.value?.sampleCount || 0,
    duplicates: state.value?.duplicates || 0,
    warnings: Array.isArray(state.value?.warnings) ? state.value.warnings : [],
    topCorrCount: Array.isArray(state.value?.topCorr) ? state.value.topCorr.length : 0,
    topAnovaCount: Array.isArray(state.value?.topAnova) ? state.value.topAnova.length : 0,
  });
}

function run(){
  if (!props.rows?.length) {
    state.value = null;
    loading.value = false;
    error.value = '';
    emitSummary();
    return;
  }
  loading.value = true;
  error.value = '';
  emitSummary();
  worker.postMessage({ rows: props.rows, sampleSize: 1000, numericHint: [] });
}
onMounted(()=> {
  worker.onmessage = (e) => {
    const { ok, data, error: workerError } = e.data || {};
    if (!ok) {
      state.value = null;
      loading.value = false;
      error.value = workerError || 'Profile analysis failed.';
      emitSummary();
      return;
    }
    state.value = data || null;
    loading.value = false;
    error.value = '';
    emitSummary();
  };
  worker.onerror = () => {
    state.value = null;
    loading.value = false;
    error.value = 'Profile worker crashed.';
    emitSummary();
  };
  run();
});
onBeforeUnmount(()=> worker.terminate());
watch(() => props.rows, run);
</script>

<template>
  <div class="p-3 border rounded space-y-3">
    <div class="flex items-center gap-2">
      <h3 class="font-semibold">Profile</h3>
      <span v-if="loading" class="text-xs text-gray-500">Analyzing sample...</span>
      <span v-else-if="error" class="text-xs text-red-600">{{ error }}</span>
      <span v-else-if="state" class="text-xs text-gray-500">Sample based on {{ state.sampleCount }} rows</span>
    </div>

    <div v-if="state?.warnings?.length" class="text-xs text-amber-700 bg-amber-50 border border-amber-200 p-2 rounded">
      <div v-for="(w,i) in state.warnings" :key="i">- {{ w }}</div>
    </div>

    <div v-if="state" class="grid md:grid-cols-3 gap-3 text-sm">
      <div class="p-2 border rounded">
        <div class="font-medium mb-1">Column Summary</div>
        <div class="max-h-60 overflow-auto">
          <table class="w-full">
            <thead><tr><th class="text-left">Column</th><th>Type</th><th>null</th><th>unique</th></tr></thead>
            <tbody>
              <tr v-for="(p,c) in state.profile" :key="c">
                <td class="pr-2">{{ c }}</td>
                <td class="text-center">{{ p.type }}</td>
                <td class="text-center">{{ p.nullPct }}%</td>
                <td class="text-center">{{ p.unique }}</td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>

      <div class="p-2 border rounded">
        <div class="font-medium mb-1">Duplicate Rows (sample)</div>
        <div class="text-2xl">{{ state.duplicates }}</div>
        <div class="text-xs text-gray-500">Counted from fully identical rows in sample.</div>
      </div>

      <div class="p-2 border rounded">
        <div class="font-medium mb-1">Correlation TOP10 (numeric)</div>
        <div class="max-h-60 overflow-auto">
          <ul>
            <li v-for="p in state.topCorr" :key="p.x+'-'+p.y">
              {{ p.x }} / {{ p.y }} : <b>{{ p.r }}</b>
            </li>
          </ul>
        </div>
      </div>

      <div class="p-2 border rounded md:col-span-3">
        <div class="font-medium mb-1">ANOVA TOP10 (category -> numeric)</div>
        <div class="max-h-60 overflow-auto">
          <table class="w-full">
            <thead><tr><th>Category</th><th>Numeric</th><th>F</th><th>p</th></tr></thead>
            <tbody>
              <tr v-for="a in state.topAnova" :key="a.cat+'-'+a.y">
                <td>{{ a.cat }}</td><td>{{ a.y }}</td><td>{{ a.F }}</td><td>{{ a.p }}</td>
              </tr>
            </tbody>
          </table>
        </div>
        <div class="text-xs text-gray-500 mt-1">* Sample-based exploratory metrics only. Verify with full data for final decisions.</div>
      </div>
    </div>
  </div>
</template>

